1	//! R1 — signature block: `builtins:` / `functions:` / `equations:`.
2	//!
3	//! Renders the declared signature as the theory echo's first section,
4	//! performing the OBSERVABLE closure over builtins (all oracle-pinned; see
5	//! workspace/BEHAVIOR.md "Signature section" for probe provenance):
6	//!
7	//!   * only diffie-hellman / bilinear-pairing / multiset / natural-numbers /
8	//!     xor keep a `builtins:` entry, in exactly that canonical order;
9	//!     bilinear-pairing induces diffie-hellman; every other builtin expands
10	//!     into function/equation entries instead;
11	//!   * the base pairing symbols `fst/1, pair/2, snd/1` and the two projection
12	//!     equations are always present (`dest-pairing` flips fst/snd to
13	//!     `[destructor]`);
14	//!   * functions dedup and sort byte-wise; attributes render
15	//!     `[private,constructor]` / `[private,destructor]` / `[destructor]` /
16	//!     nothing;
17	//!   * equations dedup exactly and sort byte-wise on their rendered text;
18	//!   * layout: builtins and functions are `text prefix <> fsep` fill lines;
19	//!     the equations block is all-or-nothing — one line when it fits the
20	//!     73-column ribbon, otherwise one equation per line at indent 4; an
21	//!     overlong equation drops `= rhs` to (equation indent − 2).
22	
23	use crate::ast::{Equation, FunctionDecl, Signature, SortHint, Term, VarSpec};
24	use crate::doc::{
25	    beside_op, char, fsep, nest, punctuate, render_with, sep, text, vcat, Doc,
26	};
27	use crate::term::{self, RIBBON, WIDTH};
28	
29	/// Header comment above the declarations (byte-exact from every capture).
30	const HEADER: &str = "// Function signature and definition of the equational theory E";
31	
32	/// Full signature section: header comment, blank line, then the declaration
33	/// lines (`builtins:` only when it has surviving entries).
34	pub fn render(sig: &Signature) -> String {
35	    render_with(WIDTH, RIBBON, &block_doc(sig))
36	}
37	
38	pub(crate) fn block_doc(sig: &Signature) -> Doc {
39	    let mut lines = vec![text(HEADER), text("")];
40	    let builtin_names = builtins_line_entries(&sig.builtins);
41	    if !builtin_names.is_empty() {
42	        lines.push(fill_line(
43	            "builtins: ",
44	            builtin_names.iter().map(|n| text(n)).collect(),
45	        ));
46	    }
47	    lines.push(fill_line(
48	        "functions: ",
49	        merged_function_items(sig).iter().map(|s| text(s)).collect(),
50	    ));
51	    lines.push(equations_doc(sig));
52	    vcat(lines)
53	}
54	
55	/// `text prefix <> fsep (punctuate ',' items)`: comma attached to the
56	/// preceding item, fill space between items, continuation aligned after the
57	/// prefix (probe:b_all, probe:b_revealing-signing).
58	fn fill_line(prefix: &str, items: Vec<Doc>) -> Doc {
59	    beside_op(text(prefix), fsep(punctuate(&char(','), items)))
60	}
61	
62	// ── builtins line ───────────────────────────────────────────────────────────
63	
64	/// The five builtins with a line entry, in canonical order (probe:b_all).
65	const LINE_ORDER: [&str; 5] = [
66	    "diffie-hellman",
67	    "bilinear-pairing",
68	    "multiset",
69	    "natural-numbers",
70	    "xor",
71	];
72	
73	fn builtins_line_entries(declared: &[String]) -> Vec<&'static str> {
74	    let mut present = [false; 5];
75	    for b in declared {
76	        match b.as_str() {
77	            "diffie-hellman" => present[0] = true,
78	            // bilinear-pairing induces diffie-hellman (probe:b_bilinear-pairing).
79	            "bilinear-pairing" => {
80	                present[0] = true;
81	                present[1] = true;
82	            }
83	            "multiset" => present[2] = true,
84	            "natural-numbers" => present[3] = true,
85	            "xor" => present[4] = true,
86	            _ => {}
87	        }
88	    }
89	    LINE_ORDER
90	        .iter()
91	        .zip(present)
92	        .filter_map(|(n, p)| p.then_some(*n))
93	        .collect()
94	}
95	
96	// ── functions line ──────────────────────────────────────────────────────────
97	
98	fn decl(name: &str, arity: usize, private: bool, destructor: bool) -> FunctionDecl {
99	    FunctionDecl {
100	        name: name.into(),
101	        arity,
102	        private,
103	        destructor,
104	    }
105	}
106	
107	/// `name/arity` + attribute suffix (probe:f_attrs): `private` implies a
108	/// role keyword is shown too; a public destructor shows `[destructor]` alone;
109	/// a public constructor shows nothing.
110	fn function_item(d: &FunctionDecl) -> String {
111	    let mut s = format!("{}/{}", d.name, d.arity);
112	    if d.private || d.destructor {
113	        let mut attrs: Vec<&str> = Vec::new();
114	        if d.private {
115	            attrs.push("private");
116	        }
117	        attrs.push(if d.destructor { "destructor" } else { "constructor" });
118	        s.push('[');
119	        s.push_str(&attrs.join(","));
120	        s.push(']');
121	    }
122	    s
123	}
124	
125	/// Base + builtin-expansion + user function symbols, deduped and byte-sorted.
126	/// Sorting the full item text equals sorting by name (`/` orders below every
127	/// identifier character), matching probe:f_sort.
128	fn merged_function_items(sig: &Signature) -> Vec<String> {
129	    let mut decls: Vec<FunctionDecl> = base_functions(&sig.builtins);
130	    for b in &sig.builtins {
131	        decls.extend(builtin_functions(b));
132	    }
133	    decls.extend(sig.functions.iter().cloned());
134	    let mut items: Vec<String> = decls.iter().map(function_item).collect();
135	    items.sort();
136	    items.dedup();
137	    items
138	}
139	
140	/// Always-present pairing symbols; `dest-pairing` flips the projections to
141	/// destructors (probe:b_none, probe:b_dest-pairing).
142	fn base_functions(declared: &[String]) -> Vec<FunctionDecl> {
143	    let dest = declared.iter().any(|b| b == "dest-pairing");
144	    vec![
145	        decl("fst", 1, false, dest),
146	        decl("pair", 2, false, false),
147	        decl("snd", 1, false, dest),
148	    ]
149	}
150	
151	/// Function symbols induced by one declared builtin (probes:b_*; compatibility
152	/// content learned from oracle output).
153	fn builtin_functions(name: &str) -> Vec<FunctionDecl> {
154	    match name {
155	        "hashing" => vec![decl("h", 1, false, false)],
156	        "asymmetric-encryption" | "dest-asymmetric-encryption" => vec![
157	            decl("adec", 2, false, name.starts_with("dest-")),
158	            decl("aenc", 2, false, false),
159	            decl("pk", 1, false, false),
160	        ],
161	        "signing" | "dest-signing" => vec![
162	            decl("pk", 1, false, false),
163	            decl("sign", 2, false, false),
164	            decl("true", 0, false, false),
165	            decl("verify", 3, false, name.starts_with("dest-")),
166	        ],
167	        "symmetric-encryption" | "dest-symmetric-encryption" => vec![
168	            decl("sdec", 2, false, name.starts_with("dest-")),
169	            decl("senc", 2, false, false),
170	        ],
171	        "revealing-signing" => vec![
172	            decl("getMessage", 1, false, false),
173	            decl("pk", 1, false, false),
174	            decl("revealSign", 2, false, false),
175	            decl("revealVerify", 3, false, false),
176	            decl("true", 0, false, false),
177	        ],
178	        "locations-report" => vec![
179	            decl("check_rep", 2, false, true),
180	            decl("get_rep", 1, false, true),
181	            decl("rep", 2, true, false),
182	            decl("report", 1, false, false),
183	        ],
184	        _ => Vec::new(),
185	    }
186	}
187	
188	// ── equations block ─────────────────────────────────────────────────────────
189	
190	/// `sep (header : map (nest 4) (punctuate ',' eqs))`: one line when it fits,
191	/// otherwise header alone and one equation per line at indent 4
192	/// (probe:e_mid, probe:e_conv, target:Tutorial).
193	fn equations_doc(sig: &Signature) -> Doc {
194	    let header = if sig.convergent {
195	        "equations [convergent]:"
196	    } else {
197	        "equations:"
198	    };
199	    let eqs = merged_equations(sig);
200	    let mut elems = vec![text(header)];
201	    for d in punctuate(&char(','), eqs.iter().map(equation_doc).collect()) {
202	        elems.push(nest(4, &d));
203	    }
204	    sep(elems)
205	}
206	
207	/// `sep [lhs, nest (-2) ("= " <> rhs)]`: one line `lhs = rhs`; an overlong
208	/// equation drops `= rhs` to (equation indent − 2) (probe:e_long).
209	fn equation_doc(eq: &Equation) -> Doc {
210	    sep(vec![
211	        term::doc(&eq.lhs),
212	        nest(-2, &beside_op(text("= "), term::doc(&eq.rhs))),
213	    ])
214	}
215	
216	/// One-line text of an equation — the dedup/sort key (probe:e_adedup pins
217	/// byte order on this rendered text; probe:e_dup pins exact-dedup).
218	fn equation_key(eq: &Equation) -> String {
219	    render_with(isize::MAX / 2, isize::MAX / 2, &equation_doc(eq))
220	}
221	
222	/// Base + builtin-expansion + user equations, deduped and byte-sorted on
223	/// their rendered text.
224	fn merged_equations(sig: &Signature) -> Vec<Equation> {
225	    let mut eqs = base_equations();
226	    for b in &sig.builtins {
227	        eqs.extend(builtin_equations(b));
228	    }
229	    eqs.extend(sig.equations.iter().cloned());
230	    let mut keyed: Vec<(String, Equation)> =
231	        eqs.into_iter().map(|e| (equation_key(&e), e)).collect();
232	    keyed.sort_by(|a, b| a.0.cmp(&b.0));
233	    keyed.dedup_by(|a, b| a.0 == b.0);
234	    keyed.into_iter().map(|(_, e)| e).collect()
235	}
236	
237	/// `x.<i>` — the variable spelling in builtin-induced equations
238	/// (probe:b_none and every builtin expansion probe).
239	fn xv(i: u64) -> Term {
240	    Term::Var(VarSpec {
241	        name: "x".into(),
242	        idx: i,
243	        sort: SortHint::Untagged,
244	        typ: None,
245	    })
246	}
247	
248	fn app(f: &str, args: Vec<Term>) -> Term {
249	    Term::App(f.into(), args)
250	}
251	
252	fn eq(lhs: Term, rhs: Term) -> Equation {
253	    Equation { lhs, rhs }
254	}
255	
256	/// `fst(<x.1, x.2>) = x.1`, `snd(<x.1, x.2>) = x.2` (probe:b_none).
257	fn base_equations() -> Vec<Equation> {
258	    vec![
259	        eq(app("fst", vec![Term::Pair(vec![xv(1), xv(2)])]), xv(1)),
260	        eq(app("snd", vec![Term::Pair(vec![xv(1), xv(2)])]), xv(2)),
261	    ]
262	}
263	
264	/// Equations induced by one declared builtin (probes:b_*).
265	fn builtin_equations(name: &str) -> Vec<Equation> {
266	    match name {
267	        // adec(aenc(x.1, pk(x.2)), x.2) = x.1
268	        "asymmetric-encryption" | "dest-asymmetric-encryption" => vec![eq(
269	            app(
270	                "adec",
271	                vec![
272	                    app("aenc", vec![xv(1), app("pk", vec![xv(2)])]),
273	                    xv(2),
274	                ],
275	            ),
276	            xv(1),
277	        )],
278	        // verify(sign(x.1, x.2), x.1, pk(x.2)) = true
279	        "signing" | "dest-signing" => vec![eq(
280	            app(
281	                "verify",
282	                vec![
283	                    app("sign", vec![xv(1), xv(2)]),
284	                    xv(1),
285	                    app("pk", vec![xv(2)]),
286	                ],
287	            ),
288	            app("true", vec![]),
289	        )],
290	        // sdec(senc(x.1, x.2), x.2) = x.1
291	        "symmetric-encryption" | "dest-symmetric-encryption" => vec![eq(
292	            app(
293	                "sdec",
294	                vec![app("senc", vec![xv(1), xv(2)]), xv(2)],
295	            ),
296	            xv(1),
297	        )],
298	        // getMessage(revealSign(x.1, x.2)) = x.1
299	        // revealVerify(revealSign(x.1, x.2), x.1, pk(x.2)) = true
300	        "revealing-signing" => vec![
301	            eq(
302	                app("getMessage", vec![app("revealSign", vec![xv(1), xv(2)])]),
303	                xv(1),
304	            ),
305	            eq(
306	                app(
307	                    "revealVerify",
308	                    vec![
309	                        app("revealSign", vec![xv(1), xv(2)]),
310	                        xv(1),
311	                        app("pk", vec![xv(2)]),
312	                    ],
313	                ),
314	                app("true", vec![]),
315	            ),
316	        ],
317	        // check_rep(rep(x.1, x.2), x.2) = x.1 ; get_rep(rep(x.1, x.2)) = x.1
318	        "locations-report" => vec![
319	            eq(
320	                app(
321	                    "check_rep",
322	                    vec![app("rep", vec![xv(1), xv(2)]), xv(2)],
323	                ),
324	                xv(1),
325	            ),
326	            eq(app("get_rep", vec![app("rep", vec![xv(1), xv(2)])]), xv(1)),
327	        ],
328	        _ => Vec::new(),
329	    }
330	}
