1	//! A faithful Rust port of the Hughes/Peyton-Jones pretty-printing library
2	//! `Text.PrettyPrint.HughesPJ` (Haskell `pretty` 1.1.3.6, BSD-licensed).
3	//!
4	//! OUT OF THE GPL-ERASURE SURFACE: this layout algebra was clean-roomed by the
5	//! graphdot cluster from the sanctioned BSD source
6	//! (`graphdot/sanctioned/pretty-1.1.3.6/src/Text/PrettyPrint/Annotated/
7	//! HughesPJ.hs`) and is vendored here unchanged (BSD terms permit), plus one
8	//! addition: [`render_with`], a renderer entry point taking an explicit
9	//! integer ribbon width (the theory echo uses width 110 / ribbon 73).
10	//!
11	//! This module implements the `Doc` document model and the combinators, the
12	//! best/fits layout selection, and the `PageMode` renderer: `<>`/`<+>`,
13	//! `$$`/`$+$`, `hcat`/`hsep`/`vcat`, `sep`/`cat`, `fsep`/`fcat`, `nest`/
14	//! `hang`, and the `best`/`nicest`/`fits` fitting logic with `lineLength` and
15	//! `ribbonsPerLine`.
16	//!
17	//! Nothing in this file is tamarin-specific: it is the general layout algebra.
18	//! WHICH combinators the theory echo applies, with what literal strings and
19	//! nesting, is derived from black-box probes and lives in the sibling modules
20	//! (`term`, `signature`, …); this module is the exact engine they feed.
21	//!
22	//! The annotation machinery of the original is elided (this port renders to a
23	//! plain `String`), so `TextBeside` carries the text and its column width
24	//! directly instead of an `AnnotDetails`.
25	//!
26	//! **Evaluation strategy.** The Haskell original relies on lazy evaluation: the
27	//! combinators (`sep`/`fill`/`beside`/`aboveNest`) describe exponentially large
28	//! sets of layouts as union trees, but `best` only ever forces the branches it
29	//! inspects, and `fits` only forces the *first line* of a candidate. A naive
30	//! strict port materializes those whole trees (exponential in the number of
31	//! fill elements). This port mirrors the laziness explicitly: recursive
32	//! combinator continuations are built as [`Doc::Lazy`] thunks (forced on
33	//! demand, memoized), and the `nicest` union choice uses [`fits_ahead`], which
34	//! decides `fits (min w r - sl) (best' ...)` by walking the *unresolved*
35	//! branch's first line only. Both are pure evaluation-order mirrors of the
36	//! sanctioned semantics: the resolved layout is byte-identical.
37	
38	use std::cell::RefCell;
39	use std::rc::Rc;
40	
41	/// The abstract document type. A `Doc` denotes a *set* of layouts; a `Doc` with
42	/// no `Union`/`NoDoc` denotes a single layout. Mirrors the Haskell `Doc a`
43	/// constructors (annotations elided).
44	#[derive(Clone, Debug)]
45	pub enum Doc {
46	    /// An empty span (`empty`): no height, no width.
47	    Empty,
48	    /// `text "" $$ x` — a newline above `x`. Its argument is never `Empty`.
49	    NilAbove(Rc<Doc>),
50	    /// `text s <> x` — literal text (with its column width) beside `x`. The
51	    /// argument is never a `Nest`.
52	    TextBeside(Rc<str>, usize, Rc<Doc>),
53	    /// `nest k x` — indent `x` by `k` columns (`k` may be negative).
54	    Nest(isize, Rc<Doc>),
55	    /// `ul \`union\` ur` — a choice between two layouts that flatten equal.
56	    Union(Rc<Doc>, Rc<Doc>),
57	    /// The empty *set* of documents.
58	    NoDoc,
59	    /// `Beside l sep r` — `sep` = true means a space is inserted between.
60	    Beside(Rc<Doc>, bool, Rc<Doc>),
61	    /// `Above u never_overlap l` — `never_overlap` = true forbids overlap.
62	    Above(Rc<Doc>, bool, Rc<Doc>),
63	    /// A suspended sub-document (the strict mirror of a Haskell thunk):
64	    /// computed on first [`force`], then memoized. Only ever wraps an already
65	    /// *reduced* document (an RDoc — no `Beside`/`Above`).
66	    Lazy(Rc<LazyDoc>),
67	}
68	
69	/// The shared state of a [`Doc::Lazy`] thunk.
70	pub struct LazyDoc(RefCell<LazyState>);
71	
72	enum LazyState {
73	    Pending(Option<Box<dyn FnOnce() -> Doc>>),
74	    Forced(Doc),
75	}
76	
77	impl std::fmt::Debug for LazyDoc {
78	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
79	        match &*self.0.borrow() {
80	            LazyState::Pending(_) => write!(f, "Lazy(<pending>)"),
81	            LazyState::Forced(d) => write!(f, "Lazy({:?})", d),
82	        }
83	    }
84	}
85	
86	use Doc::*;
87	
88	fn rc(d: Doc) -> Rc<Doc> {
89	    Rc::new(d)
90	}
91	
92	/// Suspend a document computation (a thunk). The closure runs at most once.
93	fn lazy<F: FnOnce() -> Doc + 'static>(f: F) -> Doc {
94	    Lazy(Rc::new(LazyDoc(RefCell::new(LazyState::Pending(Some(
95	        Box::new(f),
96	    ))))))
97	}
98	
99	/// Force a document to its outermost non-`Lazy` constructor (shallow clone —
100	/// children stay shared via `Rc`). Thunks are computed once and memoized;
101	/// chains of thunks collapse to the final value.
102	fn force(d: &Doc) -> Doc {
103	    match d {
104	        Lazy(l) => {
105	            if let LazyState::Forced(v) = &*l.0.borrow() {
106	                return v.clone();
107	            }
108	            let f = match &mut *l.0.borrow_mut() {
109	                LazyState::Pending(f) => f.take().expect("re-entrant force"),
110	                LazyState::Forced(v) => return v.clone(),
111	            };
112	            let v = force(&f());
113	            *l.0.borrow_mut() = LazyState::Forced(v.clone());
114	            v
115	        }
116	        _ => d.clone(),
117	    }
118	}
