717	/// Signature block of a capture: the `// Function signature …` header, the
718	/// blank line after it, then the contiguous non-blank declaration lines.
719	fn extract_block(capture: &str) -> Option<String> {
720	    let lines: Vec<&str> = capture.lines().collect();
721	    let start = lines
722	        .iter()
723	        .position(|l| l.starts_with("// Function signature"))?;
724	    let mut end = start + 2; // header + blank line
725	    while end < lines.len() && !lines[end].is_empty() {
726	        end += 1;
727	    }
728	    Some(lines[start..end].join("\n"))
729	}
