735	    let dir = std::path::Path::new("../../round1/targets");
736	    if !dir.is_dir() {
737	        return;
738	    }
739	    for (file, fixture) in round1_fixtures() {
740	        let capture = std::fs::read_to_string(dir.join(file))
741	            .unwrap_or_else(|e| panic!("reading {file}: {e}"));
742	        let expected = extract_block(&capture)
743	            .unwrap_or_else(|| panic!("no signature block found in {file}"));
744	        assert_eq!(
745	            render_signature_block(&fixture),
746	            expected,
747	            "signature-block divergence vs capture {file}"
748	        );
749	    }
750	}
