        msg("xlongvariablename1"),
        msg("ylongvariablename2"),
        msg("xlongvariablename1"),
    ]);
    let ms = vec![
        mac(
            "m1",
            vec![msg("x"), msg("y")],
            app("h", vec![Term::Pair(vec![msg("x"), msg("y")])]),
        ),
        mac("m2", vec![], app("h", vec![Term::PubLit("c".into())])),
        mac(
            "mlongernameAAAAAAAAAAAAAAAA",
            vec![msg("xlongvariablename1"), msg("ylongvariablename2")],
            app("h", vec![long_pair]),
