        "        mlongernameAAAAAAAAAAAAAAAA( xlongvariablename1,",
        "                                     ylongvariablename2 ) =  h(<xlongvariablename1, ylongvariablename2, ",
        "                                                                xlongvariablename1>)",
    ]
    .join("\n");
    assert_eq!(pretty_clean::macros::render_macros(&ms), expected);

    // target:issue777.
